// Universal Code Node: Maps contact form fields to database schema
// First name and last name come directly from form (no splitting needed)

// ============================================
// COMMON FIELD MAPPINGS
// ============================================

// 1. First Name & Last Name: Direct mapping (no splitting needed)
const firstName = ($input.item.json.firstName || $input.item.json.first_name || '').trim() || 'Unknown';
const lastName = ($input.item.json.lastName || $input.item.json.last_name || '').trim() || 'User';

// 2. Email: Direct mapping (NOT NULL in DB)
const email = ($input.item.json.email || '').trim();

// 3. Service/Project Type: Common mapping (now using service_interest)
const serviceNeed = (
  $input.item.json.service_interest || 
  $input.item.json.serviceNeed || 
  $input.item.json.projectNeed || 
  $input.item.json.serviceInterestedIn || 
  ''
).trim() || null;

// 4. Message: Direct mapping (NOT NULL in DB - must have value)
const message = (
  $input.item.json.message || 
  $input.item.json.projectDetails || 
  ''
).trim() || 'No message provided';

// 5. Company: Direct mapping (nullable)
const companyName = (
  $input.item.json.company || 
  $input.item.json.companyName || 
  ''
).trim() || null;

// 6. Phone: Direct mapping (NOT NULL in DB - must have value)
const phone = ($input.item.json.phone || '').trim() || null;

// 7. Budget: Format to notes (nullable)
const budget = ($input.item.json.budget || '').trim() || null;
const notes = budget ? `Budget: ${budget}` : null;

// 8. WhatsApp Same: Boolean from form (now using whatsapp_same)
const whatsappSame = $input.item.json.whatsapp_same === true || $input.item.json.whatsappSame === true || $input.item.json.whatsappSame === 'yes' || false;

// 9. Property URL: Only Real Estate sends this (NOT NULL in DB)
const propertyUrl = $input.item.json.property_url || $input.item.json.propertyUrl || null;

// 10. Client ID: From form hidden field
const clientId = $input.item.json.client_id || $input.item.json.clientId || '';

// ============================================
// PREPARE RESULT WITH ALL REQUIRED FIELDS
// ===========================================

const result = {
  first_name: firstName,
  last_name: lastName,
  email: email,
  message: message,
  service_need: serviceNeed,
  company_name: companyName,
  notes: notes,
  whatsapp_same: whatsappSame,
  source: $input.item.json.source || 'website-contact-us',
  status: 'New',
  client_id: clientId
};

// Handle phone and property_url (both NOT NULL - must always have values)
if (clientId === 'real-estate-client-1') {
  // Real Estate: Phone from form, property_url from form
  result.phone = phone || 'Not Available';
  result.property_url = propertyUrl || 'N/A';
} else if (clientId === 'supreme-animation') {
  // Animation Studio: Phone optional, property_url is 'N/A'
  result.phone = phone || 'Not Available';
  result.property_url = 'N/A';
} else if (clientId === 'signage-client-1') {
  // Signage Company: Phone optional, property_url is 'N/A'
  result.phone = phone || 'Not Available';
  result.property_url = 'N/A';
} else {
  // Default/fallback
  result.phone = phone || 'Not Available';
  result.property_url = 'N/A';
}

return { json: result };
